// n8n Code node (JavaScript)
// Goal: take ANY shape (voice or text outputs with varying fields)
// and aggregate all meaningful text into one string: aggregated_text

// --- Helpers ---
function isString(x) {
  return typeof x === 'string' && x.trim().length > 0;
}

function secondsToHMS(sec) {
  const s = Math.max(0, Number(sec) || 0);
  const h = Math.floor(s / 3600);
  const m = Math.floor((s % 3600) / 60);
  const r = Math.floor(s % 60);
  return [h, m, r].map(v => String(v).padStart(2, '0')).join(':');
}

// Recursively collect human-meaningful strings from any object/array
function collectStrings(node, path = [], bag = []) {
  if (node == null) return bag;

  // Prefer well-known text fields first
  if (typeof node === 'object' && !Array.isArray(node)) {
    // Common patterns
    if (isString(node.text)) bag.push(node.text.trim());
    if (node.extendedTextMessage?.text && isString(node.extendedTextMessage.text)) {
      bag.push(node.extendedTextMessage.text.trim());
    }
    if (isString(node.caption)) bag.push(node.caption.trim());
    if (isString(node.textMessage)) bag.push(node.textMessage.trim());

    // Data arrays like: { data: [{ text, usage: { seconds }}, ...] }
    if (Array.isArray(node.data)) {
      for (const seg of node.data) {
        if (isString(seg.text)) bag.push(seg.text.trim());
        // Optional usage metadata
        const secs = seg?.usage?.seconds;
        if (typeof secs === 'number') {
          bag.push(`[duration ${secondsToHMS(secs)}]`);
        }
      }
    }

    // Generic fallback: walk all props
    for (const [k, v] of Object.entries(node)) {
      // Avoid double-pushing known keys already handled
      if (k === 'text' || k === 'caption' || k === 'textMessage' || k === 'extendedTextMessage' || k === 'data') continue;
      collectStrings(v, path.concat(k), bag);
    }
    return bag;
  }

  if (Array.isArray(node)) {
    for (let i = 0; i < node.length; i++) {
      collectStrings(node[i], path.concat(String(i)), bag);
    }
    return bag;
  }

  // Primitive string fallback
  if (isString(node)) bag.push(node.trim());
  return bag;
}

// --- Main ---
const raw = [];

// Normalize input: items can be [{json: <obj|array>}...]
for (const it of items) {
  const j = it.json;
  if (Array.isArray(j)) raw.push(...j);
  else raw.push(j);
}

// Extract strings from everything we got
const pieces = [];
for (const obj of raw) {
  collectStrings(obj, [], pieces);
}

// De-dup consecutive identical lines, trim, and join
const cleaned = [];
for (const p of pieces) {
  const t = p.replace(/\s+/g, ' ').trim();
  if (t && t !== cleaned[cleaned.length - 1]) cleaned.push(t);
}

return [
  {
    json: {
      aggregated_text: cleaned.join('\n'),
      segments_found: cleaned.length,
    },
  },
];

// n8n Code node (JavaScript)

const all = [];

// Normalize input: support array items, a single item that's an array, or { messages: [...] }
for (const item of items) {
  const j = item.json;
  if (Array.isArray(j)) all.push(...j);
  else if (Array.isArray(j.messages)) all.push(...j.messages);
  else all.push(j);
}

// Collect text-only entries (and quoted text messages)
const texts = [];

for (const m of all) {
  // Plain text messages
  if (m?.typeMessage === 'textMessage' && typeof m.textMessage === 'string' && m.textMessage.trim()) {
    texts.push({
      ts: m.timestamp || 0,
      senderId: m.senderId || m.participant || 'unknown',
      senderName: m.senderName || m.senderContactName || 'Unknown',
      text: m.textMessage.trim(),
    });
  }

  // Quoted messages that contain a textMessage payload
  if (m?.typeMessage === 'quotedMessage' && m?.quotedMessage?.typeMessage === 'textMessage') {
    const qText = m.quotedMessage.textMessage;
    if (typeof qText === 'string' && qText.trim()) {
      texts.push({
        ts: m.timestamp || 0,
        senderId: m.quotedMessage.participant || 'unknown',
        senderName: m.senderName || m.senderContactName || 'Unknown',
        text: `(quoted) ${qText.trim()}`,
      });
    }
  }
}

// Sort ascending by time (oldest -> newest)
texts.sort((a, b) => (a.ts || 0) - (b.ts || 0));

// Build a single string for AI context
const lines = texts.map(t => {
  const iso = t.ts ? new Date(t.ts * 1000).toISOString() : '';
  return `${iso} | ${t.senderName} (${t.senderId}): ${t.text}`;
});

const context = lines.join('\n');

return [
  {
    json: {
      context_text: context,          // <- feed this to your AI node
      messages_count: texts.length,   // handy for debugging/guards
    },
  },
];

